// Convert Tuff if/else expression to JS ternary: if(cond) a else b => cond ? a : b
function convertIfElse(expr: string): string {
  const prefix = "if (";
  const idx = expr.indexOf(prefix);
  if (idx !== 0) return expr;

  // Find matching closing paren for the condition
  let depth = 0;
  let condEnd = -1;
  for (let i = idx + prefix.length - 1; i < expr.length; i++) {
    if (expr[i] === "(") depth++;
    else if (expr[i] === ")") {
      depth--;
      if (depth === 0) {
        condEnd = i;
        break;
      }
    }
  }
  if (condEnd === -1) return expr;

  const condition = expr.substring(idx + prefix.length, condEnd);
  let rest = expr.substring(condEnd + 1).trim();

  // Find the "else" keyword that separates then/else branches
  elseSearch: for (let i = 0; i < rest.length - 4; i++) {
    if (rest.substring(i, i + 5) === "else") {
      const thenBranch = rest.substring(0, i).trim();
      const elseBranch = rest.substring(i + 4).trim();
      return "(" + condition + ") ? (" + thenBranch + ") : (" + elseBranch + ")";
    }
  }

  return expr;
}

